<template>
  <view class="cart-container">
    <!-- 得物风顶部导航栏 -->
    <TopNavbar activePage="cart" />
    
    <view class="cart-content-body">
      <!-- 购物车为空 -->
      <view class="empty-cart" v-if="cartList.length === 0">
        <image src="/static/images/empty.png" mode="aspectFit" class="empty-img"></image>
        <text class="empty-text">购物车空空如也，快去挑选心仪商品吧~</text>
        <button class="go-shopping-btn" @click="goHome">去逛逛</button>
      </view>

      <!-- 购物车列表 -->
      <view class="cart-list" v-else>
        <!-- 顶部操作栏 -->
        <view class="cart-header">
          <view class="header-left" v-if="isEditing">
            <checkbox :checked="isAllSelected" @tap="handleAllSelect"></checkbox>
            <text class="all-select-text">全选</text>
          </view>
          <view class="header-right">
            <button v-if="!isEditing" class="batch-delete-btn" @click="toggleEditing">批量删除</button>
            <view v-else class="edit-actions">
              <button class="cancel-edit-btn" @click="toggleEditing">取消</button>
              <button class="confirm-delete-btn" @click="showDeleteModal">删除</button>
            </view>
          </view>
        </view>

       <!-- 商品列表 -->
        <view class="cart-item" v-for="(item, index) in cartList" :key="index">
          <checkbox v-if="isEditing" :checked="item.checked" @tap="handleItemSelect(index)"></checkbox>
          <image :src="item.productImage" mode="aspectFill" class="cart-item-img"></image>
          <view class="cart-item-info">
            <text class="cart-item-name" @click="goToProductDetail(item.productId)">{{item.productName}}</text>
            <text class="cart-item-spec">规格：{{item.specText}}</text>
            <view class="item-bottom">
              <text class="cart-item-price">¥{{item.price.toFixed(2)}}</text>
              <view class="quantity-control">
                <button class="quantity-btn" @click="handleQuantityChange(index, 'minus')" :disabled="item.quantity <= 1">-</button>
                <input type="number" class="quantity-input" :value="item.quantity" @blur="(e) => handleQuantityInput(index, e)">
                <button class="quantity-btn" @click="handleQuantityChange(index, 'plus')" :disabled="item.quantity >= item.stock">+</button>
              </view>
            </view>
          </view>
          <!-- 正常模式下显示单项删除，编辑模式下隐藏 -->
          <button v-if="!isEditing" class="item-delete-btn" @click="deleteSingleItem(index)">删除</button>
        </view>
      </view>
    </view>

    <!-- 底部结算 (保持在最外层，因为它有 fixed 定位) -->
    <view class="cart-footer" v-if="cartList.length > 0">
      <view class="total-info">
        <text class="total-text">合计：</text>
        <text class="total-price">¥{{totalPrice.toFixed(2)}}</text>
      </view>
      <view class="footer-btns">
        <button 
          class="cancel-btn" 
          :class="{ 'active': hasChanged }" 
          :disabled="!hasChanged" 
          @click="handleRollback"
        >取消</button>
        <button 
          class="save-btn" 
          :class="{ 'active': hasChanged }" 
          :disabled="!hasChanged" 
          @click="handleSave"
        >保存</button>
        <button class="settle-btn" @click="goToConfirmOrder" :disabled="selectedCount <= 0 || isEditing">结算</button>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref, computed } from 'vue';
import { onShow, onHide } from '@dcloudio/uni-app';
import { useCartStore } from '@/store/modules/cartStore';
import TopNavbar from '@/components/business/TopNavbar.vue';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const cartStore = useCartStore();
const userStore = useUserStore();
// 页面数据
const cartList = ref([]); // 购物车列表
const isEditing = ref(false); // 是否处于编辑模式（批量删除模式）
const originalCartList = ref([]); // 用于回滚的原始数据

// 计算属性：是否有未保存的修改（支持删除和数量变化检测）
const hasChanged = computed(() => {
  // 1. 检查长度是否变化（是否有删除）
  if (cartList.value.length !== originalCartList.value.length) return true;
  
  // 2. 检查现有商品数量是否与原始备份一致
  return cartList.value.some(item => {
    const originalItem = originalCartList.value.find(o => o.productId === item.productId && o.specId === item.specId);
    // 如果找不到原始项（理论上长度一致时不会发生）或者数量不一致，则认为已修改
    return !originalItem || Number(item.quantity) !== Number(originalItem.quantity);
  });
});

// 计算属性：全选状态
const isAllSelected = computed({
  get: () => {
    return cartList.value.length > 0 && cartList.value.every(item => item.checked);
  },
  set: (val) => {
    cartList.value.forEach(item => {
      item.checked = val;
    });
  }
});

// 计算属性：选中商品总数、选中商品总价
const selectedCount = computed(() => {
  // 始终计算购物车内所有商品的总件数，保持模式切换时的一致性
  return cartList.value.reduce((total, item) => total + item.quantity, 0);
});

const totalPrice = computed(() => {
  // 始终计算购物车内所有商品的总价格，保持模式切换时的一致性
  return cartList.value.reduce((total, item) => total + (item.price * item.quantity), 0);
});

// 计算总件数（所有商品数量之和，用于未编辑模式下的结算或展示）
const totalCount = computed(() => {
  return cartList.value.reduce((total, item) => total + item.quantity, 0);
});

// 接口请求：获取购物车列表
const getCartList = async () => {
  uni.showLoading({ title: '加载中' });
  try {
    const res = await request({
      url: '/api/cart/list',
      method: 'GET'
    });
    if (res && res.success && Array.isArray(res.data)) {
      console.log('购物车数据请求成功:', res.data);
      cartList.value = res.data.map(item => ({
        ...item, 
        checked: false,
        // 确保价格和数量是数值
        price: Number(item.price) || 0,
        quantity: Number(item.quantity) || 1,
        // 确保规格文本存在
        specText: item.specText || '默认规格'
      }));
      // 备份原始数据用于回滚
      originalCartList.value = JSON.parse(JSON.stringify(cartList.value));
    } else {
      console.warn('购物车数据格式异常或请求失败:', res);
      cartList.value = [];
    }
  } catch (error) {
    uni.showToast({ title: '购物车加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 切换编辑模式
const toggleEditing = () => {
  isEditing.value = !isEditing.value;
  // 进入编辑模式时，默认不选中任何商品
  if (isEditing.value) {
    cartList.value.forEach(item => item.checked = false);
  }
};

// 全选/取消全选
const handleAllSelect = () => {
  isAllSelected.value = !isAllSelected.value;
};

// 单个商品选择
const handleItemSelect = (index) => {
  cartList.value[index].checked = !cartList.value[index].checked;
};

// 数量修改
let debounceTimer = null;
const handleQuantityChange = (index, type) => {
  const item = cartList.value[index];
  let newQuantity = item.quantity;
  if (type === 'plus') {
    newQuantity += 1;
    // 校验库存
    if (newQuantity > item.stock) {
      uni.showToast({ title: '库存不足', icon: 'none' });
      return;
    }
  } else if (type === 'minus') {
    if (newQuantity <= 1) return;
    newQuantity -= 1;
  }
  
  // 更新本地数据
  cartList.value[index].quantity = newQuantity;
  
  // 防抖逻辑（按要求实现，300ms内不重复提示或处理）
  if (debounceTimer) clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    // 仅作视图更新，不触发接口
  }, 300);
};

// 输入数量修改
const handleQuantityInput = (index, e) => {
  let newQuantity = parseInt(e.detail.value);
  const item = cartList.value[index];
  
  // 校验合法性
  if (isNaN(newQuantity) || newQuantity < 1) {
    newQuantity = 1;
  } else if (newQuantity > item.stock) {
    newQuantity = item.stock;
    uni.showToast({ title: `库存不足，最大可购${item.stock}件`, icon: 'none' });
  }
  
  // 更新本地数据
  cartList.value[index].quantity = newQuantity;
};

// 保存修改到云端
const handleSave = async () => {
  if (!hasChanged.value) return;
  
  uni.showLoading({ title: '保存中' });
  try {
    const cartItems = cartList.value.map(item => ({
      productId: item.productId,
      specId: item.specId,
      quantity: item.quantity
    }));
    
    const res = await request({
      url: '/api/cart/update',
      method: 'PUT',
      data: { cartItems }
    });
    
    if (res.success) {
      uni.showToast({ title: '保存成功' });
      uni.removeStorageSync('cart_cache');
      uni.removeStorageSync('cart_original_cache');
      // 更新原始数据备份
      originalCartList.value = JSON.parse(JSON.stringify(cartList.value));
      // 同步Pinia状态
      cartStore.syncCart();
    } else {
      throw new Error(res.message || '保存失败');
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
    // 回滚本地视图
    cartList.value = JSON.parse(JSON.stringify(originalCartList.value));
    uni.removeStorageSync('cart_cache');
    uni.removeStorageSync('cart_original_cache');
  } finally {
    uni.hideLoading();
  }
};

// 取消修改并回滚
const handleRollback = () => {
  if (!hasChanged.value) return;
  uni.showModal({
    title: '提示',
    content: '您确定要取消之前的修改吗?',
    success: (res) => {
      if (res.confirm) {
        cartList.value = JSON.parse(JSON.stringify(originalCartList.value));
        uni.removeStorageSync('cart_cache');
        uni.removeStorageSync('cart_original_cache');
        uni.showToast({ title: '已取消', icon: 'none' });
      }
    }
  });
};

// 单个商品删除（仅前端缓存移除，保存时统一同步）
const deleteSingleItem = (index) => {
  uni.showModal({
    title: '提示',
    content: '确定要从购物车移除该商品吗？',
    success: (res) => {
      if (res.confirm) {
        cartList.value.splice(index, 1);
        uni.showToast({ title: '已移除，请记得保存', icon: 'none' });
      }
    }
  });
};

// 批量删除相关
const showDeleteModal = () => {
  const selectedItems = cartList.value.filter(item => item.checked);
  if (selectedItems.length === 0) {
    uni.showToast({ title: '请选择要删除的商品', icon: 'none' });
    return;
  }
  
  uni.showModal({
    title: '提示',
    content: '确定要移除选中的商品吗？',
    success: (res) => {
      if (res.confirm) {
        confirmDelete();
      }
    }
  });
};

const confirmDelete = () => {
  const selectedItems = cartList.value.filter(item => item.checked);
  if (selectedItems.length === 0) return;
  
  // 仅在本地进行过滤，不调用接口
  cartList.value = cartList.value.filter(item => !item.checked);
  uni.showToast({ title: '已移除，请记得保存', icon: 'none' });
  isEditing.value = false;
};

const performSettle = (items) => {
  // 跳转并携带选中商品数据
  uni.navigateTo({
    url: `/pages/order/confirm/confirm?cartItems=${encodeURIComponent(JSON.stringify(items))}`
  });
};

// 跳转至订单确认页
const goToConfirmOrder = () => {
  const selectedItems = cartList.value.filter(item => item.checked);
  // 如果不在编辑模式，且没有勾选任何商品（因为勾选框被隐藏了），则结算全部商品
  let itemsToSettle = selectedItems;
  if (!isEditing.value && selectedItems.length === 0) {
    itemsToSettle = cartList.value;
  }
  
  if (itemsToSettle.length === 0) {
    uni.showToast({ title: '购物车是空的', icon: 'none' });
    return;
  }
  
  // 如果有未保存的修改，提示用户先保存
  if (hasChanged.value) {
    uni.showModal({
      title: '提示',
      content: '您有未保存的修改，是否先保存？',
      confirmText: '去保存',
      cancelText: '直接结算',
      success: (res) => {
        if (res.confirm) {
          handleSave();
        } else {
          performSettle(itemsToSettle);
        }
      }
    });
  } else {
    performSettle(itemsToSettle);
  }
};

// 页面跳转
const goHome = () => {
  uni.reLaunch({ url: '/pages/main/index/index' });
};

const goToProductDetail = (productId) => {
  uni.navigateTo({ url: `/pages/product/detail/detail?productId=${productId}` });
};

// 页面显示时获取购物车数据
onShow(() => {
  // 优先从缓存读取未保存的修改
  const cachedCart = uni.getStorageSync('cart_cache');
  const cachedOriginal = uni.getStorageSync('cart_original_cache');
  
  // 检查缓存
  if (Array.isArray(cachedCart) && cachedCart.length > 0 && Array.isArray(cachedOriginal)) {
    cartList.value = cachedCart;
    originalCartList.value = cachedOriginal;
  } else {
    // 无效或空缓存则清理并请求新数据
    uni.removeStorageSync('cart_cache');
    uni.removeStorageSync('cart_original_cache');
    
    if (userStore.token || userStore.isLogin) {
      getCartList();
    } else {
      // 未登录，获取本地临时购物车
      const tempCart = uni.getStorageSync('cartTemp') || [];
      cartList.value = tempCart.map(item => ({ 
        ...item, 
        checked: false,
        price: Number(item.price) || 0,
        quantity: Number(item.quantity) || 1
      }));
      originalCartList.value = JSON.parse(JSON.stringify(cartList.value));
    }
  }
});

// 页面隐藏时持久化未保存的修改
onHide(() => {
  if (hasChanged.value) {
    uni.setStorageSync('cart_cache', cartList.value);
    uni.setStorageSync('cart_original_cache', originalCartList.value);
  }
});
</script>

